package com.weeklycommit.ai.provider;

/**
 * Strategy interface for AI suggestion providers.
 *
 * <p>
 * Implementations must be idempotent and must never throw unchecked exceptions
 * that would bubble up to the caller — all errors must be surfaced via
 * {@link AiSuggestionResult#unavailable()}.
 */
public interface AiProvider {

	/** Unique, human-readable name for this provider (e.g., "stub", "openai"). */
	String getName();

	/** Model/version identifier used for audit and reproducibility. */
	String getVersion();

	/**
	 * Returns {@code true} when the provider is reachable and ready.
	 *
	 * <p>
	 * This is a fast health check; implementations should cache results and avoid
	 * expensive round-trips on every call.
	 */
	boolean isAvailable();

	/**
	 * Generates a suggestion for the given context.
	 *
	 * <p>
	 * Must never throw. Returns {@link AiSuggestionResult#unavailable()} if the
	 * provider is down or an internal error occurs.
	 *
	 * @param context
	 *            the input context
	 * @return the suggestion result, never {@code null}
	 */
	AiSuggestionResult generateSuggestion(AiContext context);

	/**
	 * Generates a suggestion using the given {@code modelOverride} instead of the
	 * provider's configured default model.
	 *
	 * <p>
	 * Providers that support per-request model selection (e.g.
	 * {@code OpenRouterAiProvider}) should override this method. The default
	 * implementation ignores the override and delegates to
	 * {@link #generateSuggestion(AiContext)}.
	 *
	 * @param context
	 *            the input context
	 * @param modelOverride
	 *            the model identifier to use, or {@code null} to use the default
	 * @return the suggestion result, never {@code null}
	 */
	default AiSuggestionResult generateSuggestion(AiContext context, String modelOverride) {
		return generateSuggestion(context);
	}
}

package com.weeklycommit.ai.provider;

import java.util.Map;

/**
 * Result returned by an {@link AiProvider}.
 *
 * <p>
 * When {@code available} is {@code false}, all other fields are meaningless and
 * callers should propagate {@code aiAvailable: false} to their response without
 * failing the request.
 */
public record AiSuggestionResult(
		/** {@code false} when the provider is down or AI is disabled. */
		boolean available,
		/**
		 * JSON-serialised suggestion payload. Structure varies by
		 * {@link AiContext#suggestionType()}.
		 */
		String payload,
		/** Human-readable rationale explaining why the suggestion was made. */
		String rationale,
		/**
		 * Provider confidence in the primary suggestion [0.0, 1.0]. Used for RCDO
		 * suggestions to filter below the surfacing threshold.
		 */
		double confidence,
		/** Provider model identifier for audit and reproducibility. */
		String modelVersion,
		/**
		 * Prompt template version identifier for A/B testing (e.g.
		 * "commit-draft-assist-v1"). May be null for older results.
		 */
		String promptVersion,
		/**
		 * Experiment variant assignments active for this request, keyed by experiment
		 * name (e.g. {@code "llm-model"} → {@code "treatment"}). Empty when no
		 * experiments were evaluated.
		 */
		Map<String, String> experimentAssignments) {

	/**
	 * Backward-compatible constructor for callers that provide a prompt version but
	 * no experiment assignments.
	 */
	public AiSuggestionResult(boolean available, String payload, String rationale, double confidence,
			String modelVersion, String promptVersion) {
		this(available, payload, rationale, confidence, modelVersion, promptVersion, Map.of());
	}

	/**
	 * Backward-compatible constructor for callers that do not yet provide a prompt
	 * version or experiment assignments.
	 */
	public AiSuggestionResult(boolean available, String payload, String rationale, double confidence,
			String modelVersion) {
		this(available, payload, rationale, confidence, modelVersion, null, Map.of());
	}

	/** Convenience factory for an unavailable (degraded) result. */
	public static AiSuggestionResult unavailable() {
		return new AiSuggestionResult(false, "{}", "AI provider unavailable", 0.0, "none", null, Map.of());
	}
}

package com.weeklycommit.ai.provider;

import com.fasterxml.jackson.core.JsonProcessingException;
import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.databind.node.ArrayNode;
import com.fasterxml.jackson.databind.node.ObjectNode;
import java.io.IOException;
import java.net.URI;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.time.Duration;
import java.time.Instant;
import java.util.Map;
import java.util.concurrent.atomic.AtomicLong;
import java.util.concurrent.atomic.AtomicReference;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.boot.autoconfigure.condition.ConditionalOnProperty;
import org.springframework.core.io.ClassPathResource;
import org.springframework.stereotype.Component;

/**
 * Production AI provider that routes requests through OpenRouter.
 *
 * <p>
 * Activated when {@code ai.provider=openrouter} (the default). Falls back to
 * unavailable when the API key is blank or the service is unreachable.
 *
 * <p>
 * Features:
 * <ul>
 * <li>Per-suggestion-type prompt templates loaded from classpath</li>
 * <li>Cached health check (60 s TTL) to avoid hammering the API</li>
 * <li>Simple rate limiting via token-bucket (10 req/min default)</li>
 * <li>Token counting from response headers for cost tracking</li>
 * <li>Structured output mode (response_format=json_object) eliminates markdown
 * fence parsing</li>
 * <li>One-retry fallback if the model returns non-JSON content</li>
 * </ul>
 */
@Component
@ConditionalOnProperty(name = "ai.provider", havingValue = "openrouter", matchIfMissing = true)
public class OpenRouterAiProvider implements AiProvider {

	private static final Logger log = LoggerFactory.getLogger(OpenRouterAiProvider.class);

	private final String apiKey;
	private final String model;
	private final int maxTokens;
	private final String baseUrl;
	private final ObjectMapper objectMapper;
	private final HttpClient httpClient;

	/** Cached availability result: [timestamp, available]. */
	private final AtomicReference<Instant> lastHealthCheck = new AtomicReference<>(Instant.EPOCH);
	private volatile boolean lastHealthResult = false;
	private static final Duration HEALTH_CACHE_TTL = Duration.ofSeconds(60);

	/** Simple rate limiter: track request count per minute window. */
	private final AtomicLong windowStart = new AtomicLong(System.currentTimeMillis());
	private final AtomicLong windowCount = new AtomicLong(0);
	private static final int MAX_REQUESTS_PER_MINUTE = 30;

	/** Running totals for observability. */
	private final AtomicLong totalTokensUsed = new AtomicLong(0);
	private final AtomicLong totalRequests = new AtomicLong(0);

	/** Prompt-cache token counters (Anthropic models via OpenRouter). */
	private final AtomicLong cacheCreationTokens = new AtomicLong(0);
	private final AtomicLong cacheReadTokens = new AtomicLong(0);

	public OpenRouterAiProvider(@Value("${ai.openrouter.api-key:}") String apiKey,
			@Value("${ai.openrouter.model:anthropic/claude-sonnet-4-20250514}") String model,
			@Value("${ai.openrouter.max-tokens:1024}") int maxTokens,
			@Value("${ai.openrouter.base-url:https://openrouter.ai/api/v1}") String baseUrl,
			ObjectMapper objectMapper) {
		this.apiKey = apiKey;
		this.model = model;
		this.maxTokens = maxTokens;
		this.baseUrl = baseUrl;
		this.objectMapper = objectMapper;
		this.httpClient = HttpClient.newBuilder().connectTimeout(Duration.ofSeconds(10)).build();

		if (apiKey == null || apiKey.isBlank()) {
			log.warn("OpenRouter API key is blank — provider will report unavailable");
		} else {
			log.info("OpenRouterAiProvider initialized: model={}, maxTokens={}", model, maxTokens);
		}
		log.info("Prompt caching enabled for Anthropic models");
	}

	// ── AiProvider contract ──────────────────────────────────────────────

	@Override
	public String getName() {
		return "openrouter";
	}

	@Override
	public String getVersion() {
		return model;
	}

	@Override
	public boolean isAvailable() {
		if (apiKey == null || apiKey.isBlank()) {
			return false;
		}
		// Cached health check
		Instant now = Instant.now();
		if (Duration.between(lastHealthCheck.get(), now).compareTo(HEALTH_CACHE_TTL) < 0) {
			return lastHealthResult;
		}
		// Fresh check — just verify the API key works with a tiny request
		try {
			HttpRequest req = HttpRequest.newBuilder().uri(URI.create(baseUrl + "/models"))
					.header("Authorization", "Bearer " + apiKey).timeout(Duration.ofSeconds(5)).GET().build();
			HttpResponse<String> resp = httpClient.send(req, HttpResponse.BodyHandlers.ofString());
			lastHealthResult = resp.statusCode() == 200;
		} catch (Exception e) {
			log.debug("OpenRouter health check failed: {}", e.getMessage());
			lastHealthResult = false;
		}
		lastHealthCheck.set(now);
		return lastHealthResult;
	}

	@Override
	public AiSuggestionResult generateSuggestion(AiContext context) {
		return generateSuggestion(context, null);
	}

	@Override
	public AiSuggestionResult generateSuggestion(AiContext context, String modelOverride) {
		if (apiKey == null || apiKey.isBlank()) {
			return AiSuggestionResult.unavailable();
		}

		// Rate limiting
		if (!tryAcquireRate()) {
			log.warn("OpenRouter rate limit exceeded for type={}", context.suggestionType());
			return AiSuggestionResult.unavailable();
		}

		String effectiveModel = (modelOverride != null && !modelOverride.isBlank()) ? modelOverride : this.model;
		String promptVersion = resolvePromptVersion(context.suggestionType());
		String systemPrompt = loadPromptTemplate(context.suggestionType());
		String userMessage = buildUserMessage(context);

		// Retry loop: if the model returns non-JSON content, retry once
		for (int attempt = 1; attempt <= 2; attempt++) {
			try {
				String responseBody = callOpenRouter(systemPrompt, userMessage, effectiveModel);
				totalRequests.incrementAndGet();
				return parseResponse(responseBody, context.suggestionType(), promptVersion, effectiveModel);
			} catch (ParseException e) {
				if (attempt < 2) {
					log.warn("OpenRouter response parse failed for type={} (attempt {}), retrying: {}",
							context.suggestionType(), attempt, e.getMessage());
				} else {
					log.warn("OpenRouter response parse failed after retry for type={}: {}", context.suggestionType(),
							e.getMessage());
					return AiSuggestionResult.unavailable();
				}
			} catch (Exception e) {
				log.warn("OpenRouter request failed for type={}: {}", context.suggestionType(), e.getMessage());
				return AiSuggestionResult.unavailable();
			}
		}

		return AiSuggestionResult.unavailable();
	}

	// ── HTTP call ────────────────────────────────────────────────────────

	private String callOpenRouter(String systemPrompt, String userMessage, String effectiveModel)
			throws IOException, InterruptedException {
		ObjectNode body = objectMapper.createObjectNode();
		body.put("model", effectiveModel);
		body.put("max_tokens", maxTokens);

		// Structured output: forces the model to return valid JSON without markdown
		// fences
		ObjectNode responseFormat = body.putObject("response_format");
		responseFormat.put("type", "json_object");

		ArrayNode messages = body.putArray("messages");
		ObjectNode systemMsg = messages.addObject();
		systemMsg.put("role", "system");
		systemMsg.put("content", systemPrompt);
		if (effectiveModel.startsWith("anthropic/")) {
			systemMsg.putObject("cache_control").put("type", "ephemeral");
		}
		messages.addObject().put("role", "user").put("content", userMessage);

		String json = objectMapper.writeValueAsString(body);

		HttpRequest request = HttpRequest.newBuilder().uri(URI.create(baseUrl + "/chat/completions"))
				.header("Authorization", "Bearer " + apiKey).header("Content-Type", "application/json")
				.header("HTTP-Referer", "https://weeklycommit.dev").header("X-Title", "Weekly Commit")
				.timeout(Duration.ofSeconds(30)).POST(HttpRequest.BodyPublishers.ofString(json)).build();

		HttpResponse<String> response = httpClient.send(request, HttpResponse.BodyHandlers.ofString());

		if (response.statusCode() != 200) {
			throw new IOException("OpenRouter returned " + response.statusCode() + ": " + response.body());
		}

		// Track tokens from response
		try {
			JsonNode respNode = objectMapper.readTree(response.body());
			JsonNode usage = respNode.get("usage");
			if (usage != null) {
				updateUsageCounters(usage);
			}
		} catch (Exception ignored) {
		}

		return response.body();
	}

	// ── Response parsing ─────────────────────────────────────────────────

	/**
	 * Updates token counters from the OpenRouter {@code usage} JSON node.
	 *
	 * <p>
	 * Handles standard {@code total_tokens} as well as Anthropic prompt-cache
	 * fields ({@code cache_creation_input_tokens},
	 * {@code cache_read_input_tokens}). Logs cache metrics at DEBUG level.
	 *
	 * <p>
	 * Package-private for testing.
	 */
	void updateUsageCounters(JsonNode usage) {
		if (usage == null) {
			return;
		}
		if (usage.has("total_tokens")) {
			totalTokensUsed.addAndGet(usage.get("total_tokens").asLong());
		}
		long creation = 0;
		long read = 0;
		if (usage.has("cache_creation_input_tokens")) {
			creation = usage.get("cache_creation_input_tokens").asLong();
			cacheCreationTokens.addAndGet(creation);
		}
		if (usage.has("cache_read_input_tokens")) {
			read = usage.get("cache_read_input_tokens").asLong();
			cacheReadTokens.addAndGet(read);
		}
		log.debug("Cache metrics: cache_creation_input_tokens={}, cache_read_input_tokens={}", creation, read);
	}

	/**
	 * Parses the OpenRouter response body and returns an
	 * {@link AiSuggestionResult}.
	 *
	 * <p>
	 * With {@code response_format=json_object}, the model content is expected to be
	 * valid JSON directly — no markdown fence stripping needed.
	 *
	 * @throws ParseException
	 *             if the response content cannot be parsed as valid JSON (caller
	 *             should retry)
	 *
	 *             <p>
	 *             Package-private for testing.
	 */
	/**
	 * Backward-compatible 3-param overload; uses {@code this.model} as the
	 * effective model version recorded in the result.
	 */
	AiSuggestionResult parseResponse(String responseBody, String suggestionType, String promptVersion)
			throws ParseException {
		return parseResponse(responseBody, suggestionType, promptVersion, this.model);
	}

	/**
	 * Parses the OpenRouter response body and returns an
	 * {@link AiSuggestionResult}.
	 *
	 * <p>
	 * With {@code response_format=json_object}, the model content is expected to be
	 * valid JSON directly — no markdown fence stripping needed.
	 *
	 * @param effectiveModel
	 *            the model actually used for this request (may differ from
	 *            {@code this.model} when a per-request override is active)
	 * @throws ParseException
	 *             if the response content cannot be parsed as valid JSON (caller
	 *             should retry)
	 *
	 *             <p>
	 *             Package-private for testing.
	 */
	AiSuggestionResult parseResponse(String responseBody, String suggestionType, String promptVersion,
			String effectiveModel) throws ParseException {
		JsonNode root;
		try {
			root = objectMapper.readTree(responseBody);
		} catch (Exception e) {
			// The outer response envelope itself is malformed — not retry-worthy
			log.warn("Failed to parse OpenRouter response envelope for {}: {}", suggestionType, e.getMessage());
			return AiSuggestionResult.unavailable();
		}

		JsonNode choices = root.get("choices");
		if (choices == null || choices.isEmpty()) {
			return AiSuggestionResult.unavailable();
		}

		String content = choices.get(0).path("message").path("content").asText("");
		if (content.isBlank()) {
			return AiSuggestionResult.unavailable();
		}

		// With response_format=json_object the content should be valid JSON directly.
		// If it isn't, signal a retry-worthy failure via ParseException.
		JsonNode contentNode;
		try {
			contentNode = objectMapper.readTree(content);
		} catch (JsonProcessingException e) {
			throw new ParseException("Model returned non-JSON content for " + suggestionType + ": "
					+ content.substring(0, Math.min(200, content.length())), e);
		}

		// Extract rationale from the JSON payload if the model provided one
		String rationale = "AI-generated suggestion";
		JsonNode rationaleNode = contentNode.get("rationale");
		if (rationaleNode != null && !rationaleNode.isNull() && !rationaleNode.asText("").isBlank()) {
			rationale = rationaleNode.asText();
		}

		// Extract confidence from the JSON payload; default to 0.5 if absent or
		// out-of-range. Services with richer evidence context (RAG, risk) will
		// override this with an evidence-based tier in their own pipelines.
		double confidence = 0.5;
		JsonNode confidenceNode = contentNode.get("confidence");
		if (confidenceNode != null && !confidenceNode.isNull() && confidenceNode.isNumber()) {
			double parsed = confidenceNode.asDouble();
			if (parsed >= 0.0 && parsed <= 1.0) {
				confidence = parsed;
			}
		}

		return new AiSuggestionResult(true, content, rationale, confidence, effectiveModel, promptVersion);
	}

	// ── Prompt construction ──────────────────────────────────────────────

	private String loadPromptTemplate(String suggestionType) {
		String filename = switch (suggestionType) {
			case AiContext.TYPE_COMMIT_DRAFT -> "commit-draft-assist.txt";
			case AiContext.TYPE_COMMIT_LINT -> "commit-lint.txt";
			case AiContext.TYPE_RCDO_SUGGEST -> "rcdo-suggest.txt";
			case AiContext.TYPE_RISK_SIGNAL -> "risk-signal.txt";
			case AiContext.TYPE_RECONCILE_ASSIST -> "reconcile-assist.txt";
			case AiContext.TYPE_TEAM_SUMMARY -> "team-summary.txt";
			case AiContext.TYPE_RAG_INTENT -> "rag-intent.txt";
			case AiContext.TYPE_RAG_QUERY -> "rag-query.txt";
			case AiContext.TYPE_TEAM_INSIGHT -> "team-insight.txt";
			case AiContext.TYPE_PERSONAL_INSIGHT -> "personal-insight.txt";
			case AiContext.TYPE_WHAT_IF -> "what-if.txt";
			case "FAITHFULNESS_EVAL" -> "faithfulness-eval.txt";
			default -> "generic.txt";
		};
		try {
			ClassPathResource resource = new ClassPathResource("prompts/" + filename);
			return new String(resource.getInputStream().readAllBytes());
		} catch (IOException e) {
			log.debug("Prompt template not found: prompts/{}, using default", filename);
			return "You are a helpful planning assistant for a weekly commitment tool. "
					+ "Respond with valid JSON matching the expected schema.";
		}
	}

	private String buildUserMessage(AiContext context) {
		try {
			Map<String, Object> msg = Map.of("suggestionType", context.suggestionType(), "commitData",
					context.commitData() != null ? context.commitData() : Map.of(), "planData",
					context.planData() != null ? context.planData() : Map.of(), "historicalCommits",
					context.historicalCommits() != null ? context.historicalCommits() : java.util.List.of(), "rcdoTree",
					context.rcdoTree() != null ? context.rcdoTree() : java.util.List.of(), "additionalContext",
					context.additionalContext() != null ? context.additionalContext() : Map.of());
			return objectMapper.writeValueAsString(msg);
		} catch (Exception e) {
			return "{}";
		}
	}

	/**
	 * Resolves the prompt version identifier for the given suggestion type. Uses
	 * the base prompt filename as the version key with a "-v1" suffix. When A/B
	 * testing, this method can be extended to read from feature flags and load
	 * variant templates (e.g. "commit-draft-assist-v2.txt").
	 */
	private String resolvePromptVersion(String suggestionType) {
		String base = switch (suggestionType) {
			case AiContext.TYPE_COMMIT_DRAFT -> "commit-draft-assist";
			case AiContext.TYPE_COMMIT_LINT -> "commit-lint";
			case AiContext.TYPE_RCDO_SUGGEST -> "rcdo-suggest";
			case AiContext.TYPE_RISK_SIGNAL -> "risk-signal";
			case AiContext.TYPE_RECONCILE_ASSIST -> "reconcile-assist";
			case AiContext.TYPE_TEAM_SUMMARY -> "team-summary";
			case AiContext.TYPE_RAG_INTENT -> "rag-intent";
			case AiContext.TYPE_RAG_QUERY -> "rag-query";
			case AiContext.TYPE_TEAM_INSIGHT -> "team-insight";
			case AiContext.TYPE_PERSONAL_INSIGHT -> "personal-insight";
			case AiContext.TYPE_WHAT_IF -> "what-if";
			default -> "generic";
		};
		// commit-draft-assist was updated to v2 (added title length rule + example).
		if ("commit-draft-assist".equals(base)) {
			return base + "-v2";
		}
		return base + "-v1";
	}

	private boolean tryAcquireRate() {
		long now = System.currentTimeMillis();
		long windowMs = 60_000;
		if (now - windowStart.get() > windowMs) {
			windowStart.set(now);
			windowCount.set(0);
		}
		return windowCount.incrementAndGet() <= MAX_REQUESTS_PER_MINUTE;
	}

	// ── Observability ────────────────────────────────────────────────────

	/** Total tokens consumed across all requests (for metrics). */
	public long getTotalTokensUsed() {
		return totalTokensUsed.get();
	}

	/** Total requests made (for metrics). */
	public long getTotalRequests() {
		return totalRequests.get();
	}

	/** Total tokens used for prompt-cache creation (Anthropic models). */
	public long getCacheCreationTokens() {
		return cacheCreationTokens.get();
	}

	/** Total tokens served from prompt cache (Anthropic models). */
	public long getCacheReadTokens() {
		return cacheReadTokens.get();
	}

	// ── Inner types ──────────────────────────────────────────────────────

	/**
	 * Thrown by {@link #parseResponse} when the model response content is not valid
	 * JSON. The caller should retry the request.
	 *
	 * <p>
	 * Package-private for testing.
	 */
	static class ParseException extends Exception {

		ParseException(String message, Throwable cause) {
			super(message, cause);
		}
	}
}

package com.weeklycommit.ai.provider;

import com.weeklycommit.ai.experiment.ExperimentAssignment;
import com.weeklycommit.ai.experiment.ExperimentService;
import java.util.List;
import java.util.Map;
import java.util.Optional;
import java.util.UUID;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Component;

/**
 * Manages registered {@link AiProvider} implementations and exposes the active
 * provider for the application.
 *
 * <p>
 * AI can be disabled globally via the {@code ai.enabled} property (default
 * {@code true}). When disabled, {@link #isAiEnabled()} returns {@code false}
 * and {@link #generateSuggestion(AiContext)} returns
 * {@link AiSuggestionResult#unavailable()} without calling any provider.
 *
 * <p>
 * Provider selection: the first registered provider that reports
 * {@link AiProvider#isAvailable()} is used. If none are available, the result
 * is also unavailable.
 */
@Component
public class AiProviderRegistry {

	private static final Logger log = LoggerFactory.getLogger(AiProviderRegistry.class);

	@Value("${ai.enabled:true}")
	private boolean aiEnabled;

	private final List<AiProvider> providers;

	@Autowired(required = false)
	private ExperimentService experimentService;

	public AiProviderRegistry(List<AiProvider> providers) {
		this.providers = providers != null ? providers : List.of();
	}

	/**
	 * Returns {@code true} when AI is enabled via feature flag AND at least one
	 * provider is registered.
	 */
	public boolean isAiEnabled() {
		return aiEnabled && !providers.isEmpty();
	}

	/**
	 * Returns the first registered provider that reports itself as available, or
	 * {@link Optional#empty()} if none are.
	 */
	public Optional<AiProvider> getActiveProvider() {
		if (!aiEnabled) {
			log.debug("AI is disabled via feature flag");
			return Optional.empty();
		}
		return providers.stream().filter(AiProvider::isAvailable).findFirst();
	}

	/**
	 * Convenience method: generates a suggestion using the active provider, or
	 * returns {@link AiSuggestionResult#unavailable()} with graceful degradation if
	 * the provider is unavailable or AI is disabled.
	 *
	 * <p>
	 * Core workflow is never affected — callers should check
	 * {@link AiSuggestionResult#available()} on the response.
	 *
	 * @param context
	 *            the input context
	 * @return suggestion result, never {@code null}
	 */
	public AiSuggestionResult generateSuggestion(AiContext context) {
		Optional<AiProvider> provider = getActiveProvider();
		if (provider.isEmpty()) {
			log.debug("No active AI provider; returning unavailable result for type={}", context.suggestionType());
			return AiSuggestionResult.unavailable();
		}
		try {
			return provider.get().generateSuggestion(context);
		} catch (Exception ex) {
			log.warn("AI provider threw exception for type={}: {}", context.suggestionType(), ex.getMessage());
			return AiSuggestionResult.unavailable();
		}
	}

	/**
	 * Experiment-aware variant of {@link #generateSuggestion(AiContext)}.
	 *
	 * <p>
	 * When an {@link ExperimentService} is wired and the {@code llm-model}
	 * experiment is enabled, the active variant's model value is passed to the
	 * provider as a per-request override. The variant assignment is recorded in
	 * {@link AiSuggestionResult#experimentAssignments()} for audit/observability.
	 *
	 * <p>
	 * Falls back to the same graceful-degradation behaviour as the base overload.
	 *
	 * @param context
	 *            the input context
	 * @param userId
	 *            caller identity used for experiment assignment (may be
	 *            {@code null})
	 * @return suggestion result, never {@code null}
	 */
	public AiSuggestionResult generateSuggestion(AiContext context, UUID userId) {
		Optional<AiProvider> provider = getActiveProvider();
		if (provider.isEmpty()) {
			log.debug("No active AI provider; returning unavailable result for type={}", context.suggestionType());
			return AiSuggestionResult.unavailable();
		}

		String modelOverride = null;
		Map<String, String> assignments = Map.of();

		if (experimentService != null) {
			String userKey = userId != null ? userId.toString() : "";
			ExperimentAssignment assignment = experimentService.assign("llm-model", userKey);
			assignments = Map.of("llm-model", assignment.variant());
			if (assignment.isTreatment() && assignment.value() != null) {
				modelOverride = assignment.value();
				log.debug("LLM A/B: using treatment model '{}' for userId={}", modelOverride, userId);
			}
		}

		try {
			AiSuggestionResult base = provider.get().generateSuggestion(context, modelOverride);
			if (!assignments.isEmpty()) {
				return new AiSuggestionResult(base.available(), base.payload(), base.rationale(), base.confidence(),
						base.modelVersion(), base.promptVersion(), assignments);
			}
			return base;
		} catch (Exception ex) {
			log.warn("AI provider threw exception for type={}: {}", context.suggestionType(), ex.getMessage());
			return AiSuggestionResult.unavailable();
		}
	}

	// Visible for testing
	boolean isAiEnabledFlag() {
		return aiEnabled;
	}

	void setAiEnabled(boolean aiEnabled) {
		this.aiEnabled = aiEnabled;
	}

	// Visible for testing
	void setExperimentService(ExperimentService experimentService) {
		this.experimentService = experimentService;
	}
}

package com.weeklycommit.ai.provider;

import static org.assertj.core.api.Assertions.assertThat;
import static org.assertj.core.api.Assertions.assertThatThrownBy;

import com.fasterxml.jackson.databind.ObjectMapper;
import java.util.List;
import java.util.Map;
import org.junit.jupiter.api.Test;

/**
 * Unit tests for OpenRouterAiProvider.
 *
 * <p>
 * Tests the provider logic without making real HTTP calls — covers availability
 * checks, rate limiting, configuration, structured-output parsing, retry
 * behaviour, and rationale extraction.
 */
class OpenRouterAiProviderTest {

	private final ObjectMapper objectMapper = new ObjectMapper();

	private OpenRouterAiProvider makeProvider(String apiKey) {
		return new OpenRouterAiProvider(apiKey, "test-model", 256, "http://localhost:0", objectMapper);
	}

	// ── Basic provider contract ──────────────────────────────────────────

	@Test
	void getName_returnsOpenrouter() {
		assertThat(makeProvider("key").getName()).isEqualTo("openrouter");
	}

	@Test
	void getVersion_returnsModel() {
		assertThat(makeProvider("key").getVersion()).isEqualTo("test-model");
	}

	@Test
	void isAvailable_blankKey_returnsFalse() {
		assertThat(makeProvider("").isAvailable()).isFalse();
		assertThat(makeProvider("  ").isAvailable()).isFalse();
	}

	@Test
	void generateSuggestion_blankKey_returnsUnavailable() {
		OpenRouterAiProvider provider = makeProvider("");
		AiContext ctx = new AiContext(AiContext.TYPE_COMMIT_DRAFT, null, null, null, Map.of(), Map.of(), List.of(),
				List.of(), Map.of());

		AiSuggestionResult result = provider.generateSuggestion(ctx);

		assertThat(result.available()).isFalse();
	}

	@Test
	void generateSuggestion_unreachableServer_returnsUnavailable() {
		// Points at localhost:0 which is unreachable
		OpenRouterAiProvider provider = makeProvider("sk-test-key");
		AiContext ctx = new AiContext(AiContext.TYPE_COMMIT_LINT, null, null, null, Map.of(), Map.of(), List.of(),
				List.of(), Map.of());

		AiSuggestionResult result = provider.generateSuggestion(ctx);

		assertThat(result.available()).isFalse();
	}

	@Test
	void rateLimiter_excessiveRequests_returnsUnavailable() {
		OpenRouterAiProvider provider = makeProvider("sk-test-key");
		AiContext ctx = new AiContext(AiContext.TYPE_COMMIT_DRAFT, null, null, null, Map.of(), Map.of(), List.of(),
				List.of(), Map.of());

		// Exhaust the rate limit (10 requests per minute)
		for (int i = 0; i < 11; i++) {
			provider.generateSuggestion(ctx);
		}
		// The 12th should definitely be rate-limited (or failed due to unreachable)
		AiSuggestionResult result = provider.generateSuggestion(ctx);
		assertThat(result.available()).isFalse();
	}

	@Test
	void tokenTracking_startsAtZero() {
		OpenRouterAiProvider provider = makeProvider("key");
		assertThat(provider.getTotalTokensUsed()).isZero();
		assertThat(provider.getTotalRequests()).isZero();
	}

	@Test
	void cacheCounters_startAtZero() {
		OpenRouterAiProvider provider = makeProvider("key");
		assertThat(provider.getCacheCreationTokens()).isZero();
		assertThat(provider.getCacheReadTokens()).isZero();
	}

	// ── Cache counter tests ──────────────────────────────────────────────

	@Test
	void updateUsageCounters_withCacheFields_updatesCacheCounters() throws Exception {
		OpenRouterAiProvider provider = makeProvider("key");

		com.fasterxml.jackson.databind.node.ObjectNode usage = objectMapper.createObjectNode();
		usage.put("total_tokens", 100);
		usage.put("cache_creation_input_tokens", 80);
		usage.put("cache_read_input_tokens", 20);

		provider.updateUsageCounters(usage);

		assertThat(provider.getTotalTokensUsed()).isEqualTo(100);
		assertThat(provider.getCacheCreationTokens()).isEqualTo(80);
		assertThat(provider.getCacheReadTokens()).isEqualTo(20);
	}

	@Test
	void updateUsageCounters_withoutCacheFields_cacheCountersRemainZero() throws Exception {
		OpenRouterAiProvider provider = makeProvider("key");

		com.fasterxml.jackson.databind.node.ObjectNode usage = objectMapper.createObjectNode();
		usage.put("total_tokens", 50);

		provider.updateUsageCounters(usage);

		assertThat(provider.getTotalTokensUsed()).isEqualTo(50);
		assertThat(provider.getCacheCreationTokens()).isZero();
		assertThat(provider.getCacheReadTokens()).isZero();
	}

	@Test
	void updateUsageCounters_calledMultipleTimes_accumulatesCounters() throws Exception {
		OpenRouterAiProvider provider = makeProvider("key");

		com.fasterxml.jackson.databind.node.ObjectNode usage1 = objectMapper.createObjectNode();
		usage1.put("cache_creation_input_tokens", 50);
		usage1.put("cache_read_input_tokens", 10);

		com.fasterxml.jackson.databind.node.ObjectNode usage2 = objectMapper.createObjectNode();
		usage2.put("cache_creation_input_tokens", 30);
		usage2.put("cache_read_input_tokens", 5);

		provider.updateUsageCounters(usage1);
		provider.updateUsageCounters(usage2);

		assertThat(provider.getCacheCreationTokens()).isEqualTo(80);
		assertThat(provider.getCacheReadTokens()).isEqualTo(15);
	}

	@Test
	void updateUsageCounters_nullNode_doesNothing() {
		OpenRouterAiProvider provider = makeProvider("key");
		provider.updateUsageCounters(null);
		assertThat(provider.getCacheCreationTokens()).isZero();
		assertThat(provider.getCacheReadTokens()).isZero();
	}

	// ── parseResponse: valid JSON response ──────────────────────────────

	@Test
	void parseResponse_validJson_returnsAvailableResult() throws Exception {
		OpenRouterAiProvider provider = makeProvider("key");
		String responseBody = """
				{
				  "choices": [{
				    "message": {
				      "role": "assistant",
				      "content": "{\\"suggestion\\": \\"be more specific\\", \\"rationale\\": \\"Clarity improves outcomes\\"}"
				    }
				  }],
				  "usage": {"total_tokens": 42}
				}
				""";

		AiSuggestionResult result = provider.parseResponse(responseBody, AiContext.TYPE_COMMIT_DRAFT, "v1");

		assertThat(result.available()).isTrue();
		assertThat(result.payload()).contains("suggestion");
		assertThat(result.modelVersion()).isEqualTo("test-model");
		assertThat(result.promptVersion()).isEqualTo("v1");
	}

	@Test
	void parseResponse_validJson_extractsRationaleFromJsonField() throws Exception {
		OpenRouterAiProvider provider = makeProvider("key");
		String responseBody = """
				{
				  "choices": [{
				    "message": {
				      "role": "assistant",
				      "content": "{\\"suggestion\\": \\"reduce scope\\", \\"rationale\\": \\"Historical data shows 60% completion\\"}"
				    }
				  }]
				}
				""";

		AiSuggestionResult result = provider.parseResponse(responseBody, AiContext.TYPE_COMMIT_DRAFT, "v1");

		assertThat(result.available()).isTrue();
		assertThat(result.rationale()).isEqualTo("Historical data shows 60% completion");
	}

	@Test
	void parseResponse_validJsonNoRationaleField_usesDefaultRationale() throws Exception {
		OpenRouterAiProvider provider = makeProvider("key");
		String responseBody = """
				{
				  "choices": [{
				    "message": {
				      "role": "assistant",
				      "content": "{\\"suggestion\\": \\"add more detail\\"}"
				    }
				  }]
				}
				""";

		AiSuggestionResult result = provider.parseResponse(responseBody, AiContext.TYPE_COMMIT_DRAFT, "v1");

		assertThat(result.available()).isTrue();
		assertThat(result.rationale()).isEqualTo("AI-generated suggestion");
	}

	// ── parseResponse: empty / missing content ───────────────────────────

	@Test
	void parseResponse_noChoices_returnsUnavailable() throws Exception {
		OpenRouterAiProvider provider = makeProvider("key");
		String responseBody = """
				{
				  "choices": []
				}
				""";

		AiSuggestionResult result = provider.parseResponse(responseBody, AiContext.TYPE_COMMIT_DRAFT, "v1");

		assertThat(result.available()).isFalse();
	}

	@Test
	void parseResponse_blankContent_returnsUnavailable() throws Exception {
		OpenRouterAiProvider provider = makeProvider("key");
		String responseBody = """
				{
				  "choices": [{
				    "message": {
				      "role": "assistant",
				      "content": ""
				    }
				  }]
				}
				""";

		AiSuggestionResult result = provider.parseResponse(responseBody, AiContext.TYPE_COMMIT_DRAFT, "v1");

		assertThat(result.available()).isFalse();
	}

	// ── parseResponse: malformed JSON content triggers ParseException ────

	@Test
	void parseResponse_malformedJsonContent_throwsParseException() {
		OpenRouterAiProvider provider = makeProvider("key");
		String responseBody = """
				{
				  "choices": [{
				    "message": {
				      "role": "assistant",
				      "content": "This is plain text, not JSON at all"
				    }
				  }]
				}
				""";

		assertThatThrownBy(() -> provider.parseResponse(responseBody, AiContext.TYPE_COMMIT_DRAFT, "v1"))
				.isInstanceOf(OpenRouterAiProvider.ParseException.class).hasMessageContaining("non-JSON content");
	}

	@Test
	void parseResponse_markdownFenceContent_throwsParseException() {
		// With response_format=json_object the model should not return fences.
		// If it does anyway, we treat it as a retry-worthy parse failure rather than
		// trying to strip the fences.
		OpenRouterAiProvider provider = makeProvider("key");
		String responseBody = """
				{
				  "choices": [{
				    "message": {
				      "role": "assistant",
				      "content": "```json\\n{\\"suggestion\\": \\"ok\\"}\\n```"
				    }
				  }]
				}
				""";

		assertThatThrownBy(() -> provider.parseResponse(responseBody, AiContext.TYPE_COMMIT_DRAFT, "v1"))
				.isInstanceOf(OpenRouterAiProvider.ParseException.class);
	}

	// ── parseResponse: model override ───────────────────────────────────

	@Test
	void parseResponse_withModelOverride_usesOverrideForModelVersion() throws Exception {
		OpenRouterAiProvider provider = makeProvider("key");
		String responseBody = """
				{
				  "choices": [{
				    "message": {
				      "role": "assistant",
				      "content": "{\\"suggestion\\": \\"ok\\"}"
				    }
				  }]
				}
				""";

		AiSuggestionResult result = provider.parseResponse(responseBody, AiContext.TYPE_COMMIT_DRAFT, "v1",
				"google/gemini-2.5-flash");

		assertThat(result.available()).isTrue();
		assertThat(result.modelVersion()).isEqualTo("google/gemini-2.5-flash");
	}

	@Test
	void parseResponse_threeParamOverload_usesProviderModel() throws Exception {
		// The 3-param backward-compat overload should use this.model ("test-model")
		OpenRouterAiProvider provider = makeProvider("key");
		String responseBody = """
				{
				  "choices": [{
				    "message": {
				      "role": "assistant",
				      "content": "{\\"suggestion\\": \\"ok\\"}"
				    }
				  }]
				}
				""";

		AiSuggestionResult result = provider.parseResponse(responseBody, AiContext.TYPE_COMMIT_DRAFT, "v1");

		assertThat(result.available()).isTrue();
		assertThat(result.modelVersion()).isEqualTo("test-model");
	}
}

package com.weeklycommit.ai.provider;

import static org.assertj.core.api.Assertions.assertThat;
import static org.mockito.ArgumentMatchers.any;
import static org.mockito.ArgumentMatchers.anyString;
import static org.mockito.ArgumentMatchers.eq;
import static org.mockito.ArgumentMatchers.isNull;
import static org.mockito.Mockito.never;
import static org.mockito.Mockito.verify;
import static org.mockito.Mockito.when;

import com.weeklycommit.ai.experiment.ExperimentAssignment;
import com.weeklycommit.ai.experiment.ExperimentService;
import java.util.List;
import java.util.UUID;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.Mock;
import org.mockito.junit.jupiter.MockitoExtension;

@ExtendWith(MockitoExtension.class)
class AiProviderRegistryTest {

	@Mock
	private AiProvider mockProvider;

	@Mock
	private ExperimentService experimentService;

	private AiProviderRegistry registry;

	@BeforeEach
	void setUp() {
		registry = new AiProviderRegistry(List.of(mockProvider));
	}

	// -------------------------------------------------------------------------
	// isAiEnabled
	// -------------------------------------------------------------------------

	@Test
	void isAiEnabled_whenFlagTrueAndProviderRegistered_returnsTrue() {
		registry.setAiEnabled(true);
		// isAiEnabled() only checks the flag + list non-empty; does not call
		// isAvailable()
		assertThat(registry.isAiEnabled()).isTrue();
	}

	@Test
	void isAiEnabled_whenFlagDisabled_returnsFalse() {
		registry.setAiEnabled(false);

		assertThat(registry.isAiEnabled()).isFalse();
	}

	@Test
	void isAiEnabled_whenNoProviders_returnsFalse() {
		AiProviderRegistry emptyRegistry = new AiProviderRegistry(List.of());

		assertThat(emptyRegistry.isAiEnabled()).isFalse();
	}

	// -------------------------------------------------------------------------
	// getActiveProvider
	// -------------------------------------------------------------------------

	@Test
	void getActiveProvider_whenProviderAvailable_returnsProvider() {
		registry.setAiEnabled(true);
		when(mockProvider.isAvailable()).thenReturn(true);

		assertThat(registry.getActiveProvider()).isPresent().contains(mockProvider);
	}

	@Test
	void getActiveProvider_whenProviderUnavailable_returnsEmpty() {
		registry.setAiEnabled(true);
		when(mockProvider.isAvailable()).thenReturn(false);

		assertThat(registry.getActiveProvider()).isEmpty();
	}

	@Test
	void getActiveProvider_whenAiDisabled_returnsEmptyWithoutCheckingProvider() {
		registry.setAiEnabled(false);

		assertThat(registry.getActiveProvider()).isEmpty();
		// Provider.isAvailable() should not be called when flag is off
		verify(mockProvider, never()).isAvailable();
	}

	// -------------------------------------------------------------------------
	// generateSuggestion — graceful degradation
	// -------------------------------------------------------------------------

	@Test
	void generateSuggestion_whenAiDisabled_returnsUnavailableWithoutCallingProvider() {
		registry.setAiEnabled(false);
		AiContext context = new AiContext(AiContext.TYPE_COMMIT_DRAFT, null, null, null, null, null, null, null, null);

		AiSuggestionResult result = registry.generateSuggestion(context);

		assertThat(result.available()).isFalse();
		verify(mockProvider, never()).generateSuggestion(any());
	}

	@Test
	void generateSuggestion_whenProviderUnavailable_returnsUnavailable() {
		registry.setAiEnabled(true);
		when(mockProvider.isAvailable()).thenReturn(false);
		AiContext context = new AiContext(AiContext.TYPE_COMMIT_DRAFT, null, null, null, null, null, null, null, null);

		AiSuggestionResult result = registry.generateSuggestion(context);

		assertThat(result.available()).isFalse();
	}

	@Test
	void generateSuggestion_whenProviderThrows_returnsUnavailable() {
		registry.setAiEnabled(true);
		when(mockProvider.isAvailable()).thenReturn(true);
		when(mockProvider.generateSuggestion(any())).thenThrow(new RuntimeException("provider error"));
		AiContext context = new AiContext(AiContext.TYPE_COMMIT_DRAFT, null, null, null, null, null, null, null, null);

		AiSuggestionResult result = registry.generateSuggestion(context);

		assertThat(result.available()).isFalse();
